### Experiment 1 (direct flag-vs-liveness repro)

I ran this exact command in `/home/bitzaven/CodingProjects/pi-threads`:

```bash
node - <<'NODE'
const { spawn } = require('node:child_process');

const child = spawn(process.execPath, ['-e', `
process.on('SIGTERM', () => {
  console.log('child: SIGTERM received, ignoring');
});
setInterval(() => {}, 1000);
`], { stdio: ['ignore', 'pipe', 'inherit'] });

child.stdout.on('data', d => process.stdout.write(String(d)));
child.on('close', (code, signal) => {
  console.log(`child close event: code=${code} signal=${signal}`);
});

setTimeout(() => {
  console.log(`parent: sending SIGTERM to pid ${child.pid}`);
  child.kill('SIGTERM');
  console.log(`parent: immediately after kill, child.killed=${child.killed}`);

  setTimeout(() => {
    console.log(`parent: 5s fallback check, child.killed=${child.killed}`);
    if (!child.killed) {
      console.log('parent: sending SIGKILL fallback');
      child.kill('SIGKILL');
    } else {
      console.log('parent: NOT sending SIGKILL because child.killed is true');
    }

    let alive = true;
    try {
      process.kill(child.pid, 0);
    } catch {
      alive = false;
    }
    console.log(`parent: is child alive after fallback gate? ${alive}`);

    if (alive) {
      console.log('parent: cleanup SIGKILL to avoid leaving orphan');
      process.kill(child.pid, 'SIGKILL');
    }

    setTimeout(() => process.exit(0), 200);
  }, 5000);
}, 500);
NODE
```

Output:

```text
parent: sending SIGTERM to pid 260307
parent: immediately after kill, child.killed=true
child: SIGTERM received, ignoring
parent: 5s fallback check, child.killed=true
parent: NOT sending SIGKILL because child.killed is true
parent: is child alive after fallback gate? true
parent: cleanup SIGKILL to avoid leaving orphan
child close event: code=null signal=SIGKILL
```

**What it shows:** `child.killed` became `true` immediately after `SIGTERM`, but the child was still alive 5s later. So gating fallback on `!proc.killed` can skip `SIGKILL` while the process is still running.

