      const killProc = () => {
        proc.kill('SIGTERM');
        setTimeout(() => {
          if (!proc.killed) proc.kill('SIGKILL');
        }, 5000);
      };
      if (signal.aborted) killProc();
      else signal.addEventListener('abort', killProc, { once: true });
    }
  });
}

(async () => {
  const ac = new AbortController();
  const runPromise = runLikeRunPiOnThread(ac.signal);

  setTimeout(() => {
    console.log('parent: aborting at t=0.5s');
    ac.abort();
  }, 500);

  const result = await Promise.race([
    runPromise,
    new Promise((resolve) => setTimeout(() => resolve({ kind: 'timeout' }), 7000)),
  ]);

  console.log('parent: race result =', result);
  console.log('parent: child.killed flag =', child?.killed);

  let alive = false;
  try {
    if (child?.pid) {
      process.kill(child.pid, 0);
      alive = true;
    }
  } catch {}
  console.log('parent: child alive after 7s =', alive);

  if (alive && child?.pid) {
    process.kill(child.pid, 'SIGKILL');
    console.log('parent: cleanup SIGKILL sent');
  }

  setTimeout(() => process.exit(0), 200);
