const THREADS_DIR = ".pi/threads";
const DEFAULT_PI_COMMAND = "pi";
const EXECUTABLE_SCRIPT_EXTENSIONS = new Set([".js", ".cjs", ".mjs", ".ts", ".cts", ".mts"]);

type RuntimeMessage = EpisodeMessage & {
