	const wireOutput = (proc: ChildProcess): (() => void) => {
		let stdoutBuffer = "";

		if (proc.stdout) {
			proc.stdout.on("data", (chunk: Buffer | string) => {
				stdoutBuffer += chunk.toString();
				const lines = stdoutBuffer.split("\n");
				stdoutBuffer = lines.pop() || "";
				for (const line of lines) {
					if (!line.trim()) continue;
					let event: StreamEvent;
					try {
						event = JSON.parse(line) as StreamEvent;
					} catch {
						continue;
					}
					if ((event.type === "message_end" || event.type === "tool_result_end") && event.message) {
						handleMessage(event.message);
					}
				}
			});
		}

		if (proc.stderr) {
			proc.stderr.on("data", (chunk: Buffer | string) => {
				const text = chunk.toString();
				stderr += text;
				emit({ type: "stderr", chunk: text });
			});
		}

		return () => {
			if (!stdoutBuffer.trim()) return;
			try {
				const event = JSON.parse(stdoutBuffer) as StreamEvent;
				if ((event.type === "message_end" || event.type === "tool_result_end") && event.message) {
					handleMessage(event.message);
				}
			} catch {
				/* ignore trailing non-json */
			}
			stdoutBuffer = "";
		};
	};

	const requestTermination = async (reason: RunTerminationReason): Promise<void> => {
		if (!child || getExitSnapshot(child)) return;
		if (typeof child.pid === "number") applyStateEvent({ type: "started", pid: child.pid });
		applyStateEvent({ type: "terminationRequested", reason });
		await terminateProcess(child, { sigtermGraceMs });
	};

	const cancel = async (reason: RunTerminationReason = "abort"): Promise<void> => {
		requestedTerminationReason ??= reason;
		if (state.tag === "exited") return;
		if (!child) return;
		if (!terminationPromise) {
			terminationPromise = requestTermination(requestedTerminationReason);
		}
		await terminationPromise;
	};

	const result = (async (): Promise<PiActorResult> => {
		let promptFile: PromptFile | null = null;
		let removeAbortListener: (() => void) | undefined;
		let finalExitCode: number | null = null;
		let finalSignal: NodeJS.Signals | null = null;

		try {
			const sessionPath = resolveSessionPath(request);
			ensureSessionDirectory(sessionPath);
			if (request.systemPrompt) promptFile = writePromptFile(request.systemPrompt);

			const args = argsBuilder(request, {
				sessionPath,
				systemPromptFile: promptFile?.filePath,
			});
			child = spawn(command, args, {
				cwd: request.cwd,
				env: process.env,
				stdio: ["ignore", "pipe", "pipe"],
				shell: false,
			});
			startedAt = Date.now();

			if (typeof child.pid === "number") applyStateEvent({ type: "started", pid: child.pid });
			if (requestedTerminationReason) void cancel(requestedTerminationReason);

			if (signal) {
				const onAbort = () => {
					void cancel("abort");
				};
				if (signal.aborted) onAbort();
				else signal.addEventListener("abort", onAbort, { once: true });
				removeAbortListener = () => signal.removeEventListener("abort", onAbort);
			}

			const flushStdout = wireOutput(child);
			const closePromise = waitForClose(child).then(() => {
				flushStdout();
			});

			const exited = await waitForExit(child);
			finalExitCode = exited.exitCode;
			finalSignal = exited.signal;
			applyStateEvent({ type: "exited", exitCode: finalExitCode, signal: finalSignal });
			await closePromise;

			if (!stopReason && finalExitCode !== null && finalExitCode !== 0) {
				stopReason = "error";
			}
		} catch (error) {
			errorMessage ??= toErrorMessage(error);
			stopReason ??= signal?.aborted || isAbortError(error) ? "aborted" : "error";

			const exited = child ? getExitSnapshot(child) : null;
			if (exited) {
				finalExitCode = exited.exitCode;
				finalSignal = exited.signal;
				applyStateEvent({ type: "exited", exitCode: finalExitCode, signal: finalSignal });
			} else if (requestedTerminationReason === "abort") {
				applyStateEvent({ type: "exited", exitCode: null, signal: null });
			}
		} finally {
			removeAbortListener?.();
			cleanupPromptFile(promptFile);
		}

		const finalState = asExitedState(state, finalExitCode, finalSignal);
		state = finalState;
		if (!stopReason && finalState.requestedTerminationReason === "abort") {
			stopReason = "aborted";
		}

		return {
			runId: request.runId,
			thread: request.thread,
			finalState,
			messages,
			stderr,
			usage,
			model: model ?? request.model,
			stopReason,
			errorMessage,
		};
	})();

	return {
		runId: request.runId,
		thread: request.thread,
		result,
		cancel,
		subscribe(listener: (event: PiActorEvent) => void): () => void {
			listeners.add(listener);
			return () => listeners.delete(listener);
		},
		getSnapshot(): PiActorSnapshot {
			return {
				runId: request.runId,
				thread: request.thread,
				pid: child?.pid,
				startedAt,
				state,
			};
		},
	};
}

export class PiActorRuntime {
	private readonly command: string;
	private readonly argsBuilder: PiActorArgsBuilder;
	private readonly defaultSigtermGraceMs: number;

	constructor(options: PiActorRuntimeOptions = {}) {
		const commandSpec = options.command
			? { command: options.command, argsPrefix: [] }
			: resolvePiCommandSpec();
		const baseArgsBuilder = options.buildArgs ?? defaultArgsBuilder;

		this.command = commandSpec.command;
		this.argsBuilder = (request, context) => [
			...commandSpec.argsPrefix,
			...baseArgsBuilder(request, context),
		];
		this.defaultSigtermGraceMs = options.defaultSigtermGraceMs ?? 5_000;
	}

	invoke(request: PiActorInvocationRequest, options: PiActorInvokeOptions = {}): PiActorHandle {
		return createInvocation({
			request,
			signal: options.signal,
			command: this.command,
			argsBuilder: this.argsBuilder,
			sigtermGraceMs: this.defaultSigtermGraceMs,
		});
	}
}

import type { ChildProcess } from "node:child_process";

export interface TerminateProcessOptions {
	sigtermGraceMs: number;
}

interface ExitSnapshot {
	exitCode: number | null;
	exitSignal: NodeJS.Signals | null;
}

export interface TerminateProcessResult extends ExitSnapshot {
	/**
	 * True when this function had to escalate to SIGKILL.
	 */
	forced: boolean;
	/**
	 * The final signal this function sent (`SIGTERM`, `SIGKILL`, or `null` when
	 * the process had already exited before termination was requested).
	 */
	signal: "SIGTERM" | "SIGKILL" | null;
}

function getExitSnapshot(child: ChildProcess): ExitSnapshot | null {
	if (child.exitCode === null && child.signalCode === null) return null;
	return {
		exitCode: child.exitCode,
		exitSignal: child.signalCode,
	};
}

function waitForExit(child: ChildProcess): Promise<ExitSnapshot> {
	const exited = getExitSnapshot(child);
	if (exited) return Promise.resolve(exited);

	return new Promise<ExitSnapshot>((resolve) => {
		const onExit = (exitCode: number | null, exitSignal: NodeJS.Signals | null) => {
			cleanup();
			resolve({ exitCode, exitSignal });
		};

		const cleanup = () => {
			child.off("exit", onExit);
		};

		child.once("exit", onExit);

		const racedExit = getExitSnapshot(child);
		if (racedExit) {
			cleanup();
			resolve(racedExit);
		}
	});
}

function waitForExitOrTimeout(child: ChildProcess, timeoutMs: number): Promise<ExitSnapshot | null> {
	const exited = getExitSnapshot(child);
	if (exited) return Promise.resolve(exited);

	return new Promise<ExitSnapshot | null>((resolve) => {
		let settled = false;

		const cleanup = () => {
			clearTimeout(timer);
			child.off("exit", onExit);
		};

		const onExit = (exitCode: number | null, exitSignal: NodeJS.Signals | null) => {
			if (settled) return;
			settled = true;
			cleanup();
			resolve({ exitCode, exitSignal });
		};

		const timer = setTimeout(() => {
			if (settled) return;
			settled = true;
			cleanup();
			resolve(null);
		}, Math.max(0, timeoutMs));

		child.once("exit", onExit);

		const racedExit = getExitSnapshot(child);
		if (racedExit && !settled) {
			settled = true;
			cleanup();
			resolve(racedExit);
		}
	});
}

const PRE_SIGTERM_SETTLE_MS = 25;

/**
 * Gracefully terminate a child process.
 *
 * Behavior:
 * 1. Allow a tiny startup settle window (for just-spawned processes to install
 *    signal handlers).
 * 2. Send SIGTERM.
 * 3. Wait up to `sigtermGraceMs` for real process exit (via exit code/signal).
 * 4. If still running, escalate to SIGKILL and wait for real exit.
 *
 * Important: this does not use `child.killed` to infer exit.
 */
export async function terminateProcess(
	child: ChildProcess,
	{ sigtermGraceMs }: TerminateProcessOptions,
): Promise<TerminateProcessResult> {
	const exitedBeforeTermination = getExitSnapshot(child);
	if (exitedBeforeTermination) {
		return {
			forced: false,
			signal: null,
			...exitedBeforeTermination,
		};
	}

	const settleMs = Math.min(Math.max(0, sigtermGraceMs), PRE_SIGTERM_SETTLE_MS);
	if (settleMs > 0) {
		const exitedDuringSettle = await waitForExitOrTimeout(child, settleMs);
		if (exitedDuringSettle) {
			return {
				forced: false,
				signal: null,
				...exitedDuringSettle,
			};
		}
	}

	child.kill("SIGTERM");

	const exitedAfterSigterm = await waitForExitOrTimeout(child, sigtermGraceMs);
	if (exitedAfterSigterm) {
		return {
			forced: false,
			signal: "SIGTERM",
			...exitedAfterSigterm,
		};
	}

	const racedExitAfterTimeout = getExitSnapshot(child);
	if (racedExitAfterTimeout) {
		return {
			forced: false,
			signal: "SIGTERM",
			...racedExitAfterTimeout,
		};
	}

	const sentSigkill = child.kill("SIGKILL");
	const finalExit = await waitForExit(child);

	if (sentSigkill) {
		return {
			forced: true,
			signal: "SIGKILL",
			...finalExit,
		};
	}

	return {
		forced: false,
		signal: "SIGTERM",
		...finalExit,
	};
}

